css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: repeating-conic-gradient(#0000,currentColor 1deg 18deg,#0000 20deg 36deg);
  animation: l9 4s infinite linear;
  position: relative;
}.loader::before{content: "";
  position: absolute;
  border-radius: 50%;
  inset:0;
  background: inherit;
  animation: inherit;
}@keyframes l9{100% {transform: rotate(.5turn)}}
